# scripts/check_critical_vulns.py
# Called from CI — exits 1 if any Critical CVE found, triggering deploy block

import json, sys

CRITICAL_CVSS_THRESHOLD = 9.0

def main():
    report_path = sys.argv[1]
    with open(report_path) as f:
        data = json.load(f)

    critical_found = []
    for dep in data.get("dependencies", []):
        for vuln in dep.get("vulns", []):
            # pip-audit includes CVSS scores in the fix field or aliases
            aliases = vuln.get("aliases", [])
            # For GenAI inference runtimes, treat any deserialization CVE as critical
            desc_lower = vuln.get("description", "").lower()
            is_deserial = any(k in desc_lower for k in ["deserializ", "pickle", "unsafe load", "arbitrary code"])
            is_inference_rt = dep["name"] in {"onnxruntime", "torch", "tensorflow", "tensorrt"}

            if is_deserial and is_inference_rt:
                critical_found.append((dep["name"], vuln["id"], "deserialization in inference runtime"))

    if critical_found:
        print("CRITICAL VULNERABILITIES — deploy blocked:")
        for pkg, cve, reason in critical_found:
            print(f"  {pkg}: {cve} ({reason})")
        sys.exit(1)
    else:
        print("No critical escalation criteria met.")
        sys.exit(0)

if __name__ == "__main__":
    main()

# compare_outputs.py — run after applying patch
import json, sys

def compare(before_path: str, after_path: str):
    with open(before_path) as f: before = {r["prompt"]: r for r in json.load(f)}
    with open(after_path) as f:  after  = {r["prompt"]: r for r in json.load(f)}

    changed = []
    for prompt, pre in before.items():
        post = after.get(prompt)
        if post and pre["response_hash"] != post["response_hash"]:
            changed.append({
                "prompt": prompt[:60],
                "before": pre["response"][:120],
                "after":  post["response"][:120],
            })

    if changed:
        print(f"WARNING: {len(changed)} response(s) changed after patch:")
        for item in changed:
            print(f"  Prompt: {item['prompt']}")
            print(f"  Before: {item['before']}")
            print(f"  After:  {item['after']}")
            print()
        # Changed responses are not necessarily regressions — review manually
        sys.exit(2)  # exit code 2 = changes detected, human review needed
    else:
        print("No response changes detected. Patch is output-stable.")
        sys.exit(0)
